def categorize_regional_dishes(dishes):
    regions = {
        'Northeast': ['cheesesteak', 'clam chowder', 'Boston baked beans'],
        'South': ['gumbo', 'fried chicken', 'biscuits'],
        'Midwest': ['deep-dish pizza', 'hotdish', 'cornbread'],
        'West': ['cioppino', 'avocado toast', 'Dungeness crab'],
        'Southwest': ['chile relleno', 'green chile stew', 'tortilla chips'],
        'Hawaii': ['poke', 'kalua pig', 'loco moco'],
        'Louisiana': ['jambalaya', 'beignets', 'po'boys']
    }
    categorized = {region: [] for region in regions}
    for dish in dishes:
        for region, dishes_in_region in regions.items():
            if dish.lower() in dishes_in_region:
                categorized[region].append(dish)
                break
    return categorized

# Example usage:
dishes = ['cheesesteak', 'gumbo', 'avocado toast', 'poke']
print(categorize_regional_dishes(dishes))
# Output: {'Northeast': ['cheesesteak'], 'South': ['gumbo'], 'West': ['avocado toast'], 'Hawaii': ['poke'], ...}
